questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values (in mH) ===== */
L1_mH: if set=1 then 25 else if set=2 then 40 else 80;
L2_mH: if set=1 then 100 else if set=2 then 90 else 100;
k:     if set=1 then 0.6 else if set=2 then 0.7 else 0.4;

/* ===== Derived values ===== */
L1: L1_mH/1000;
L2: L2_mH/1000;
M: float(k*sqrt(L1*L2));
M_mH: float(M*1000);
sqrtL1L2_mH: float(sqrt(L1_mH*L2_mH));

/* ===== T-equivalent for AIDING (both i enter dotted terminals) ===== */
/* v1 = L1 di1/dt + M di2/dt  =>  T-equiv: La + Lc = L1, Lc = M */
/* v2 = M di1/dt + L2 di2/dt  =>  T-equiv: Lb + Lc = L2, Lc = M */
La: float(L1 - M);
Lb: float(L2 - M);
Lc: float(M);
La_mH: float(La*1000);
Lb_mH: float(Lb*1000);
Lc_mH: float(Lc*1000);

/* Check if La is negative */
La_negative: is(La < 0);
k_threshold_val: float(sqrt(L1/L2));
k_threshold: float(sqrt(L1_mH/L2_mH));

/* ===== Teacher answers ===== */
ta1: float(M_mH);

/* Part (b) MCQ: Aiding or opposing */
ta2: [[1, true, "Aiding — both currents enter dotted terminals, so mutual flux reinforces self-flux"],
      [2, false, "Opposing — the currents create opposing magnetic fields"],
      [3, false, "Neither — the dot convention only matters for transformers, not coupled inductors"],
      [4, false, "Cannot determine without knowing the physical orientation of the coils"]];
ta2_correct: 1;

ta3: float(La_mH);
ta4: float(Lb_mH);
ta5: float(Lc_mH);

/* Part (d) MCQ: Negative inductance — conditional on La_negative */
ta6: if is(La_negative=true) then
       [[1, true, "Yes — La is negative because M > L1 (i.e., k > sqrt(L1/L2))"],
        [2, false, "No — all T-equivalent elements must be positive for a valid circuit"],
        [3, false, "Yes — but only because the coupling coefficient k is invalid (k > 1)"],
        [4, false, "No — negative inductance only occurs for the opposing case"]]
     else
       [[1, false, "Yes — La is negative because M > L1"],
        [2, true, "No — for these parameters, all T-equivalent elements are non-negative"],
        [3, false, "Yes — but only because the coupling coefficient k is invalid (k > 1)"],
        [4, false, "No — negative inductance is impossible in any circuit model"]];
ta6_correct: if is(La_negative=true) then 1 else 2;

/* ===== Part (e): Opposing T-equivalent Lc ===== */
/* Opposing case: Lc = -M, La = L1 + M, Lb = L2 + M */
ta7: float(-M_mH);
La_opp_mH: float((L1+M)*1000);
Lb_opp_mH: float((L2+M)*1000);
Lc_opp_mH: float(-M_mH);

/* ===== Part (f): Opposing energy sign MCQ ===== */
ta8: [[1, true, "Minus (\u2212) \u2014 opposing mutual flux reduces stored energy"],
      [2, false, "Plus (+) \u2014 all energy contributions are additive"],
      [3, false, "Zero \u2014 mutual inductance does not affect stored energy"],
      [4, false, "It depends on the values of i\u2081 and i\u2082"]];
ta8_correct: 1;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;

sa3_float: float(ans3);
ref3_float: float(ta3);
/* Use NumAbsolute if La is near zero (within 1 mH), otherwise ratio-based checks */
prt3_near_zero: if abs(ref3_float) < 1.0 then true else false;
prt3_oom_ok: if (abs(ref3_float) > 1.0e-30 and abs(sa3_float) > 1.0e-30 and (abs(sa3_float/ref3_float - 10) < 1.5 or abs(sa3_float/ref3_float - 0.1) < 0.015)) then true else false;

sa4_float: float(ans4);
ref4_float: float(ta4);
prt4_oom_ok: if (abs(ref4_float) > 1.0e-30 and abs(sa4_float) > 1.0e-30 and (abs(sa4_float/ref4_float - 10) < 1.5 or abs(sa4_float/ref4_float - 0.1) < 0.015)) then true else false;

sa5_float: float(ans5);
ref5_float: float(ta5);
prt5_oom_ok: if (abs(ref5_float) > 1.0e-30 and abs(sa5_float) > 1.0e-30 and (abs(sa5_float/ref5_float - 10) < 1.5 or abs(sa5_float/ref5_float - 0.1) < 0.015)) then true else false;
